SELECT 
    VARIANCE(uwz17.c15) AS col_1, 
    STDDEV_SAMP(uwz17.c15) AS col_1_stddev,
    DATE_FORMAT(uwz17.c13, 'HH24:MI:SS') AS col_2,
    uwz17.c2 AS grouping_col
FROM t2 AS uwz17 
WHERE DATE_FORMAT(uwz17.c13, 'HH24:MI:SS') = 'HH24:MI:SS'
GROUP BY DATE_FORMAT(uwz17.c13, 'HH24:MI:SS'), uwz17.c2
HAVING ABS(VARIANCE(uwz17.c15) - 1.0609) < 0.0001
ORDER BY uwz17.c2 DESC;
